from flask import Flask, request, jsonify
from collections import defaultdict
import numpy as np
import json

app = Flask(__name__)

# Store labels from annotators
label_storage = defaultdict(list)

@app.route('/label', methods=['POST'])
def label_image():
    data = request.json
    image_id = data['image_id']
    label = data['label']
    
    # Store the label from the annotator
    label_storage[image_id].append(label)
    return jsonify({"message": "Label received"}), 200

@app.route('/aggregate', methods=['GET'])
def aggregate_labels():
    aggregated_labels = {}
    for image_id, labels in label_storage.items():
        if labels:
            # Majority voting for the label
            majority_label = max(set(labels), key=labels.count)
            aggregated_labels[image_id] = majority_label
    return jsonify(aggregated_labels), 200

@app.route('/train', methods=['POST'])
def train_model():
    # This function would include the model training logic
    labeled_data = aggregate_labels().get_json()
    # Assume we have a function `train_on_data` to train the model
    train_on_data(labeled_data)
    return jsonify({"message": "Model training initiated"}), 200

def train_on_data(data):
    # Placeholder for actual training logic
    print("Training model with labeled data...")
    print(json.dumps(data, indent=4))

if __name__ == '__main__':
    app.run(debug=True)